    function calendar_feed_reader($url, $db_name = null, $timeout = null, $max_events = null, $drop_existing = null)
    {
            $url = $url ?? '';
            $db_name = $db_name ?? 'calendar.sqlite';
            $timeout = $timeout ?? 20;
            $max_events = $max_events ?? 500;
            $drop_existing = $drop_existing ?? false;

            $timeout = max(5, min(30, (int)$timeout));
