            }

            // Unfold continuation lines (RFC 5545: lines starting with space/tab are continuations)
            $lines_arr = preg_split('/\r\n|\n|\r/', $raw);
            $unfolded = [];
            $buffer = '';
            foreach ($lines_arr as $line) {
                if (strlen($line) > 0 && ($line[0] === ' ' || $line[0] === "\t")) {
