            }
            if ($buffer !== '') $unfolded[] = $buffer;

            // Recursive iCal component parser
            $parse_func = null;
            $parse_func = function(&$lines, &$i) use (&$parse_func) {
                $component = [
                    'type' => '',
                    'properties' => [],
                    'sub_components' => [],
                ];
